import './TransactionRow.css';

function TransactionRow({transaction, transactions, setTransactions, incomeAmount, setIncomeAmount, expenseAmount, setExpenseAmount, balanceAmount, setBalanceAmount}) {
    function deleteTransaction() {
        setTransactions(transactions.filter(t => t.id !== transaction.id)
        );
        if (transaction.type==='Income') {
            setIncomeAmount((Number(incomeAmount)-Number(transaction.amount)));
        }
        if (transaction.type==='Expense') {
            setExpenseAmount((Number(expenseAmount)-Number(transaction.amount)));
        }
        setBalanceAmount(Number(incomeAmount)-Number(expenseAmount));
    }
    return (
        <div className="row">
            <p className='transaction-type'>{transaction.type}</p>
            <p className='transaction-category'>{transaction.category}</p>
            <p className='transaction-amount'>₹{transaction.amount}</p>
            <p className='transaction-date'>{transaction.date}</p>
            <button className='delete-transaction-button' onClick={deleteTransaction}>X</button>
        </div>
    )
};

export default TransactionRow;
